from typing import List, Dict
import numpy as np
from collections import Counter

SPECIAL_TOKENS = {'[PAD]': 0, '[UNK]': 1, '[BOS]': 2, '[EOS]': 3}

def build_vocab(corpus: List[str], min_freq: int = 1) -> Dict[str, int]:
    counts = Counter()
    for doc in corpus:
        counts.update(doc.lower().split())
    # Filter by min_freq
    filtered = {w: c for w, c in counts.items() if c >= min_freq}
    # Sort: descending frequency, then alphabetical for ties
    sorted_words = sorted(filtered.keys(), key=lambda w: (-filtered[w], w))
    # Build vocab starting after special tokens
    vocab = dict(SPECIAL_TOKENS)
    next_id = len(SPECIAL_TOKENS)
    for word in sorted_words:
        if word not in vocab:  # don't overwrite special tokens
            vocab[word] = next_id
            next_id += 1
    return vocab

def encode(text: str, vocab: Dict[str, int]) -> List[int]:
    unk_id = vocab['[UNK]']
    return [vocab.get(token, unk_id) for token in text.lower().split()]

def decode(ids: List[int], vocab: Dict[str, int]) -> str:
    inv_vocab = {v: k for k, v in vocab.items()}
    return ' '.join(inv_vocab.get(i, '[UNK]') for i in ids)
